parameters.jsCode:
const anio = new Date().getFullYear();
const aleatorio = Math.random().toString(36).slice(2, 10).toUpperCase();
const codigoUnico = `MAT-${anio}-${aleatorio}`;
// TODO produccion: reemplazar por UUID real. La unicidad real la garantiza
// el UNIQUE(cedula, periodo_actual) de la tabla + el chequeo previo de
// "Buscar Certificado Existente".

const nombreCompleto = `${$json.nombres} ${$json.apellidos}`;
const fechaEmision = new Date().toLocaleDateString('es-EC', {
  year: 'numeric', month: 'long', day: '2-digit'
});
const urlVerificacion = `https://verificacion.tudominio.edu.ec/certificados/${codigoUnico}`;

return [{
  json: {
    ...$json,
    codigoUnico,
    nombreCompleto,
    fechaEmision,
    urlVerificacion
  }
}];

